// 첫 번째 pending 주제를 가져와 정규화
const topics = $input.all();
const topic = topics[0].json;

// 슬러그 생성 (한글 키워드를 URL 친화적으로)
const keyword = topic.keyword || '';
const slug = keyword
  .trim()
  .toLowerCase()
  .replace(/\s+/g, '-')
  .replace(/[^a-z0-9가-힣-]/g, '');

// topic_id 생성
const today = new Date();
const dateStr = today.toISOString().slice(0, 10).replace(/-/g, '');
const topicId = topic.topic_id || `${dateStr}-${Math.random().toString(36).substr(2, 6)}`;

// 검색 의도 분류 기본값
const intentMap = {
  '방법': 'how-to',
  '추천': 'comparison',
  '가격': 'commercial',
  '후기': 'review',
  '뜻': 'informational',
  '이란': 'informational'
};

let inferredIntent = 'informational';
for (const [key, value] of Object.entries(intentMap)) {
  if (keyword.includes(key)) {
    inferredIntent = value;
    break;
  }
}

return [{
  json: {
    ...topic,
    topic_id: topicId,
    normalized_keyword: keyword.trim(),
    slug: slug,
    inferred_intent: topic.intent || inferredIntent,
    article_brief: `키워드: ${keyword} / 독자: ${topic.audience || '1인사업자'} / 각도: ${topic.angle || '실무형 가이드'}`,
    row_index: topic.row_number || 2
  }
}];

// 수요 점수 계산 (100점 만점)
// 보고서 기준: 65점 미만 폐기

const topicData = $('Code - 주제 정규화').item.json;

// 네이버 데이터랩 결과 파싱
let naverScore = 0;
try {
  const naverData = $('HTTP Request - 네이버 데이터랩').item.json;
  if (naverData.results && naverData.results[0]) {
    const series = naverData.results[0].data || [];
    if (series.length >= 2) {
      const recentAvg = series.slice(-4).reduce((a, b) => a + b.ratio, 0) / 4;
      const prevAvg = series.slice(-8, -4).reduce((a, b) => a + b.ratio, 0) / 4;
      // 상승 추이 계산
      if (prevAvg > 0) {
        const trendRatio = recentAvg / prevAvg;
        if (trendRatio >= 1.5) naverScore = 25;      // 50% 이상 상승
        else if (trendRatio >= 1.2) naverScore = 20; // 20% 이상 상승
        else if (trendRatio >= 1.0) naverScore = 15; // 유지
        else if (trendRatio >= 0.8) naverScore = 8;  // 소폭 하락
        else naverScore = 3;                          // 급락
      } else {
        naverScore = recentAvg > 50 ? 20 : recentAvg > 20 ? 12 : 5;
      }
    }
  }
} catch(e) {
  naverScore = 10; // API 오류시 중립값
}

// Search Console 결과 파싱
let searchConsoleScore = 0;
let ctrScore = 0;
let questionScore = 0;
try {
  const scData = $('HTTP Request - Google Search Console').item.json;
  if (scData.rows && scData.rows.length > 0) {
    const totalImpressions = scData.rows.reduce((a, b) => a + (b.impressions || 0), 0);
    const avgCtr = scData.rows.reduce((a, b) => a + (b.ctr || 0), 0) / scData.rows.length;
    const avgPosition = scData.rows.reduce((a, b) => a + (b.position || 10), 0) / scData.rows.length;

    // 노출량 점수 (최대 20점)
    if (totalImpressions >= 10000) searchConsoleScore = 20;
    else if (totalImpressions >= 5000) searchConsoleScore = 16;
    else if (totalImpressions >= 1000) searchConsoleScore = 12;
    else if (totalImpressions >= 100) searchConsoleScore = 7;
    else searchConsoleScore = 3;

    // CTR 개선 가능성 (최대 15점) - CTR이 낮고 순위가 높으면 개선 여지 있음
    if (avgCtr < 0.02 && avgPosition <= 10) ctrScore = 15; // CTR 낮고 1페이지 = 큰 기회
    else if (avgCtr < 0.05 && avgPosition <= 20) ctrScore = 10;
    else if (avgCtr >= 0.1) ctrScore = 5; // 이미 잘 되고 있음
    else ctrScore = 8;

    // 질문형 쿼리 여부 (최대 15점)
    const questionWords = ['어떻게', '방법', '뜻', '이란', '추천', '비교', '가격', '후기', '장단점'];
    const hasQuestion = scData.rows.some(row => 
      questionWords.some(qw => (row.keys?.[0] || '').includes(qw))
    );
    questionScore = hasQuestion ? 15 : 5;
  } else {
    // Search Console 데이터 없음 = 새 키워드 기회
    searchConsoleScore = 8;
    ctrScore = 12; // 미발행 = 기회
    questionScore = 10;
  }
} catch(e) {
  searchConsoleScore = 8;
  ctrScore = 10;
  questionScore = 8;
}

// 전환 가능성 점수 (최대 15점) - keyword에 전환 의도 단어가 있으면 높은 점수
const conversionWords = ['추천', '구매', '비교', '가격', '상담', '신청', '등록', '예약', '구독', '방법', '사용법'];
const keyword = topicData.normalized_keyword || '';
const hasConversion = conversionWords.some(w => keyword.includes(w));
const conversionScore = hasConversion ? 15 : 8;

// 기존 글 부족도 (최대 10점) - 스프레드시트에서 이미 확인했으므로 기본값
const gapScore = 10; // 중복 체크 통과했으므로 기존 글 없음 = 만점

// 총점 계산
const totalScore = naverScore + searchConsoleScore + ctrScore + questionScore + conversionScore + gapScore;

// 판정
let priority, action;
if (totalScore >= 80) {
  priority = 'immediate';
  action = '바로 작성';
} else if (totalScore >= 65) {
  priority = 'outline_candidate';
  action = '아웃라인 후보';
} else if (totalScore >= 50) {
  priority = 'hold';
  action = '보류';
} else {
  priority = 'reject';
  action = '폐기';
}

return [{
  json: {
    ...topicData,
    demand_score: totalScore,
    score_breakdown: {
      naver_trend_25: naverScore,
      search_console_impressions_20: searchConsoleScore,
      ctr_improvement_15: ctrScore,
      question_intent_15: questionScore,
      conversion_potential_15: conversionScore,
      content_gap_10: gapScore
    },
    priority: priority,
    action: action,
    pass_threshold: totalScore >= 65
  }
}];

