} catch(e) {
  // JSON 추출 시도
  const jsonMatch = researchText.match(/\{[\s\S]+\}/);
  if (jsonMatch) {
    research = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('리서치 JSON 파싱 실패. 원문: ' + researchText.substring(0, 200));
  }
}

