  json: {
    ...topicData,
    research: research,
    research_summary: [
      `검색의도: ${research.search_intent}`,
      `핵심고충: ${research.pain_points?.slice(0,2).join(', ')}`,
      `차별화: ${research.competitive_angle}`
    ].join(' | ')
  }
}];

